import json, os, math
from pathlib import Path
base = Path('/tmp/mteb_results_full/results')
# official Scandinavian benchmark task set from mteb benchmark definition
TASKS = [
    'BornholmBitextMining','NorwegianCourtsBitextMining','AngryTweetsClassification',
    'DanishPoliticalCommentsClassification','DalajClassification','DKHateClassification',
    'LccSentimentClassification','MassiveIntentClassification','MassiveScenarioClassification',
    'NordicLangClassification','NoRecClassification','NorwegianParliamentClassification',
    'ScalaClassification','SwedishSentimentClassification','SweRecClassification',
    'DanFeverRetrieval','NorQuadRetrieval','SNLRetrieval','SwednRetrieval','SweFaqRetrieval',
    'TV2Nordretrieval','TwitterHjerneRetrieval','SNLHierarchicalClusteringS2S',
    'SNLHierarchicalClusteringP2P','SwednClusteringP2P','SwednClusteringS2S',
    'VGHierarchicalClusteringS2S','VGHierarchicalClusteringP2P'
]
TRAIN_SPLIT = {'DanishPoliticalCommentsClassification'}
VALIDATION_SPLIT = {'AFQMC','Cmnli','IFlyTek','LEMBSummScreenFDRetrieval','MSMARCO','MSMARCO-PL','MSMARCO-Fa','MultilingualSentiment','Ocnli','TNews'}
DEV_SPLIT = {'CmedqaRetrieval','CovidRetrieval','DuRetrieval','EcomRetrieval','MedicalRetrieval','MMarcoReranking','MMarcoRetrieval','MSMARCO','MSMARCO-PL','MSMARCO-Fa','T2Reranking','T2Retrieval','VideoRetrieval','TERRa','MIRACLReranking','MIRACLRetrieval'}
TESTFULL_SPLIT = {'OpusparcusPC'}
STANDARD_SPLIT = {'BrightRetrieval'}
DEVTEST_SPLIT = {'FloresBitextMining'}
TEST_AVG_SPLIT = {
    'LEMBNeedleRetrieval':['test_256','test_512','test_1024','test_2048','test_4096','test_8192','test_16384','test_32768'],
    'LEMBPasskeyRetrieval':['test_256','test_512','test_1024','test_2048','test_4096','test_8192','test_16384','test_32768'],
}
SKIP_KEYS = {'std','evaluation_time','main_score','threshold','v_measures','scores_per_experiment'}

# task -> metric path for this benchmark per task type; easiest is recursively find main_score in selected split.
def get_split(task):
    if task in TRAIN_SPLIT: return 'train'
    if task in VALIDATION_SPLIT: return 'validation'
    if task in DEV_SPLIT: return 'dev'
    if task in TESTFULL_SPLIT: return 'test.full'
    if task in STANDARD_SPLIT: return 'standard'
    if task in DEVTEST_SPLIT: return 'devtest'
    return 'test'

def extract_main_score(obj):
    if isinstance(obj, dict):
        if 'main_score' in obj and isinstance(obj['main_score'], (int,float)):
            return float(obj['main_score'])
    return None

def resolve_score(task, data):
    # prefer top-level mteb_dataset_name score split hierarchy
    split = get_split(task)
    # many files store scores under nested split dicts
    # Search exact split recursively first for main_score.
    candidates = []
    def walk(node, path=()):
        if isinstance(node, dict):
            ms = extract_main_score(node)
            if ms is not None:
                candidates.append((path, ms))
            for k,v in node.items():
                walk(v, path+(str(k),))
        elif isinstance(node, list):
            for i,v in enumerate(node):
                walk(v, path+(str(i),))
    walk(data)
    # Prefer path containing split then task language-specific leaf
    for path, ms in candidates:
        if split in path:
            return ms
    # fallback any main_score
    if candidates:
        return candidates[0][1]
    return None

scores = []
for model_dir in base.iterdir():
    if not model_dir.is_dir():
        continue
    for rev_dir in model_dir.iterdir():
        if not rev_dir.is_dir() or rev_dir.name == 'external':
            continue
        found = {}
        for task in TASKS:
            fp = rev_dir / f'{task}.json'
            if not fp.exists():
                continue
            try:
                data = json.loads(fp.read_text())
            except Exception:
                continue
            sc = resolve_score(task, data)
            if sc is not None:
                found[task] = sc
        if found:
            mean = sum(found.values())/len(found)
            model_name = model_dir.name.replace('__','/',1)
            scores.append((len(found), mean, model_name, rev_dir.name))
# require full task coverage first; print best among max coverage
maxcov = max(n for n,_,_,_ in scores)
full = [x for x in scores if x[0]==maxcov]
full.sort(key=lambda x:(-x[1], x[2]))
print('max_coverage', maxcov)
for row in full[:30]:
    print(f'{row[2]}\tmean={row[1]:.6f}\trev={row[3]}')
